import { createContext, useContext, useState } from "react";

const ThemeContext = createContext("light");

function NavItem({ label }) {
  const theme = useContext(ThemeContext);
  return <li className={`nav-item nav-item--${theme}`}>{label}</li>;
}

function Sidebar() {
  return (
    <nav>
      <NavItem label="Home" />
      <NavItem label="Settings" />
    </nav>
  );
}

function Layout({ children }) {
  return (
    <div className="layout">
      <Sidebar />
      <main>{children}</main>
    </div>
  );
}

export default function App() {
  const [theme, setTheme] = useState("light");
  return (
    <ThemeContext.Provider value={theme}>
      <Layout>
        <button onClick={() => setTheme(t => t === "light" ? "dark" : "light")}>
          Toggle theme
        </button>
      </Layout>
    </ThemeContext.Provider>
  );
}

import { useState } from "react";

let currentTheme = "light";

function NavItem({ label }) {
  return <li className={`nav-item nav-item--${currentTheme}`}>{label}</li>;
}

function Sidebar() {
  return (
    <nav>
      <NavItem label="Home" />
      <NavItem label="Settings" />
    </nav>
  );
}

function Layout({ children }) {
  return (
    <div className="layout">
      <Sidebar />
      <main>{children}</main>
    </div>
  );
}

export default function App() {
  const [theme, setTheme] = useState("light");
  currentTheme = theme;
  return (
    <Layout>
      <button onClick={() => setTheme(t => t === "light" ? "dark" : "light")}>
        Toggle theme
      </button>
    </Layout>
  );
}

import { useState } from "react";

function Sidebar({ navItems }) {
  return <nav>{navItems}</nav>;
}

function Layout({ children, navItems }) {
  return (
    <div className="layout">
      <Sidebar navItems={navItems} />
      <main>{children}</main>
    </div>
  );
}

export default function App() {
  const [theme, setTheme] = useState("light");
  const navItems = (
    <>
      <li className={`nav-item nav-item--${theme}`}>Home</li>
      <li className={`nav-item nav-item--${theme}`}>Settings</li>
    </>
  );
  return (
    <Layout navItems={navItems}>
      <button onClick={() => setTheme(t => t === "light" ? "dark" : "light")}>
        Toggle theme
      </button>
    </Layout>
  );
}
